// scripts/generate-gift-aisle-v2.js
// Expand /gifts from 48 to 144 tiles (12 categories × 12 tiles).
// 48 new tiles to fill the existing 8 cats from 6→12. 48 new tiles for 4
// new cats (book/coffee, music, nature/adventure, seasons/holidays).
//
// CRITICAL palette / mood mandate from user: more variety, more happy,
// more warm AND more cool, more colorful. The first 48 skewed too far
// toward warm-gold/nostalgic/calm. This batch deliberately spreads across
// joyful, romantic, energetic, whimsical, dreamlike palettes + mixes
// warm/cool/vibrant/jewel/pastel — so the /gifts page lights up across
// the whole range a buyer might want.
//
// Run: node scripts/generate-gift-aisle-v2.js
//
// Each spec saves to public/ai-art/moments/<name>.webp at 2:3 vertical.

import fs from 'node:fs';
import path from 'node:path';
import sharp from 'sharp';

const ROOT = process.cwd();
const OUT_DIR = path.join(ROOT, 'public', 'ai-art', 'moments');
const ENV_FILE = path.join(ROOT, '.env.local');
const MAX_DIM = 1400;
const QUALITY = 82;
const ASPECT = '2:3';

function loadApiKey() {
  if (!fs.existsSync(ENV_FILE)) throw new Error(`No .env.local at ${ENV_FILE}`);
  const raw = fs.readFileSync(ENV_FILE, 'utf8');
  for (const line of raw.split(/\r?\n/)) {
    const m = line.match(/^\s*GOOGLE_GEMINI_API_KEY\s*=\s*(.*?)\s*$/);
    if (m) {
      let v = m[1];
      if ((v.startsWith('"') && v.endsWith('"')) || (v.startsWith("'") && v.endsWith("'"))) v = v.slice(1, -1);
      if (v && v !== '[YOUR_GOOGLE_API_KEY_HERE]') return v;
    }
  }
  throw new Error('GOOGLE_GEMINI_API_KEY not present in .env.local');
}

